function defaults(){ return {profiles:[],logs:[],meals:[],water:[],photos:[],routes:[],customWorkouts:[],targets:[],metrics:[],weather:[],meds:[],routines:[],bodyScans:[],wgerCache:[],activeRoutine:null,currentRoute:null}; }
function profile(id,name){ return {id,name:name||'',birthday:'',sex:'',heightFt:'',heightIn:'',weightLb:'',level:'',goals:[],limitations:'',pinHash:null,pic:'',settings:{theme:'gold',units:'imperial',reminders:true},onboarding:{complete:false}}; }
function migrate(raw){ const base=defaults(); const s={...base,...(raw||{})}; ['profiles','logs','meals','water','photos','routes','customWorkouts','targets','metrics','weather','meds','routines','bodyScans','wgerCache'].forEach(k=>s[k]??=[]); s.profiles.forEach(p=>{p.name??='';p.birthday??='';p.sex??='';p.heightFt=p.heightFt??'';p.heightIn=p.heightIn??'';p.weightLb=p.weightLb??'';p.level=p.level||'';p.goals??=[];p.limitations??='';p.pic??='';p.settings??={theme:'gold',units:'imperial',reminders:true};p.onboarding??={complete:profileComplete(p)}; delete p.age; if(!p.birthday&&['Zayne','CAK3D'].includes(p.name)&&(!p.onboarding?.complete)) p.onboarding.complete=false;}); return s; }
function loadState(){ try{return migrate(JSON.parse(localStorage.getItem(STORAGE_KEY)))}catch{return defaults()} }
function loadAuth(){ try{return JSON.parse(localStorage.getItem(AUTH_KEY))||{profileId:null}}catch{return{profileId:null}} }
function save(){ localStorage.setItem(STORAGE_KEY,JSON.stringify(state)); localStorage.setItem(AUTH_KEY,JSON.stringify(auth)); queueCloudSave(); }
function uuid(){ return crypto.randomUUID ? crypto.randomUUID() : 'id-'+Date.now()+'-'+Math.random().toString(16).slice(2); }
function $(s){ return document.querySelector(s); }
function $all(s){ return [...document.querySelectorAll(s)]; }
function val(s){ return $(s)?.value || ''; }
function esc(v){ return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
function profileNow(){ return state.profiles.find(x=>x.id===auth.profileId) || state.profiles[0] || profile('preview',''); }
function own(arr){ const pr=profileNow(); return pr.id ? (arr||[]).filter(x=>x.profileId===pr.id) : []; }
function todayKey(d=new Date()){ return new Date(d).toDateString(); }
function profileComplete(pr=profileNow()){ return !!(pr?.name && pr?.birthday && pr?.sex && Number(pr?.heightFt)>0 && Number(pr?.weightLb)>0 && pr?.level); }
function profileStatsText(pr=profileNow()){ return profileComplete(pr) ? `${ageOf(pr)} yrs • ${pr.heightFt}'${pr.heightIn||0}" • ${pr.weightLb} lb • BMI ${bmi(pr)}` : 'Profile incomplete — add birthday, sex, height, weight, and weekly load'; }
function ageOf(pr=profileNow()){ if(pr?.birthday){ const b=new Date(pr.birthday), n=new Date(); let a=n.getFullYear()-b.getFullYear(); if(n<new Date(n.getFullYear(),b.getMonth(),b.getDate())) a--; return Math.max(0,a); } return null; }
function heightIn(pr=profileNow()){ return (+pr.heightFt||0)*12+(+pr.heightIn||0); }
function weightKg(pr=profileNow()){ return (+pr.weightLb||0)*.453592; }
function bmi(pr=profileNow()){ const h=heightIn(pr), w=+pr.weightLb||0; return h&&w ? ((w/(h*h))*703).toFixed(1) : '--'; }
function calorieTarget(pr=profileNow()){ if(!profileComplete(pr)) return null; const kg=weightKg(pr), cm=heightIn(pr)*2.54, age=ageOf(pr), sex=pr.sex==='female'?-161:5, bmr=10*kg+6.25*cm-5*age+sex; const mult={low:1.35,medium:1.55,high:1.75}[pr.level]||1.45; const g=(pr.goals||[]).join(' '); const adj=/bulk|muscle|strength/.test(g)?250:/lose|fat/.test(g)?-250:0; return Math.max(1200,Math.round(bmr*mult+adj)); }
function proteinTarget(pr=profileNow()){ return (+pr.weightLb||0) ? Math.round(+pr.weightLb*.75) : null; }
function waterTarget(pr=profileNow()){ return (+pr.weightLb||0) ? Math.round(+pr.weightLb*.55) : null; }
function requireProfileHtml(){ return `<article class="card wide warning-card"><h2>Finish your athlete profile first</h2><p>No guessed ages, weights, heights, or fake stats. Add real info so calories, water, protein, workouts, and onboarding are built around you.</p><button id="finishProfile">Enter profile data</button></article>`; }

async function hashPin(pin){ const d=await crypto.subtle.digest('SHA-256',new TextEncoder().encode('azfitness-pin:'+pin)); return [...new Uint8Array(d)].map(b=>b.toString(16).padStart(2,'0')).join(''); }


function render(){ save(); if(!auth.profileId) return renderLogin(); const pr=profileNow(); if(!profileComplete(pr)&&tab!=='profile') tab='profile'; document.body.dataset.theme=pr.settings?.theme||'gold'; $('#app').innerHTML = `<main class="app-shell android-shell"><aside class="side card nav-rail"><div class="brand"><span class="crest">A-Z</span><div><b>A-Z FITNESS</b><small>${esc(pr.name||'New athlete')} • ${pr.level||'set weekly load'}</small></div></div>${nav().map(([id,label])=>`<button class="nav ${tab===id?'active':''}" data-tab="${id}">${label}</button>`).join('')}<button class="nav ghost" id="logout">Log out / switch athlete</button><p class="tiny warning">Camera vitals are experimental wellness estimates, not medical diagnosis. For Android health sync, use Health Connect/Samsung Health export plus manual entry until native app bridge is built.</p></aside><section class="main-stage phone-stage"><header class="mobile-status"><span>9:41</span><b>A-Z Fitness</b><span>● ● ▰</span></header><header class="topbar card android-topbar"><div><p class="eyebrow">ANDROID GOLD HEALTH OS</p><h1>${headline(tab)}</h1><div class="quick-stats">${[quickStat('Readiness',profileComplete(pr)?readinessScore():'set profile'),quickStat('Water',waterTarget(pr)?waterOz()+' / '+waterTarget(pr)+' oz':'set weight'),quickStat('Target',calorieTarget(pr)?calorieTarget(pr)+' cal':'set profile')].join('')}</div></div><div class="athlete-chip">${pr.pic?`<img src="${pr.pic}" alt="">`:`<span>${esc((pr.name||'A')[0])}</span>`}<div><b>${esc(pr.name||'New athlete')}</b><small>${profileStatsText(pr)}</small></div></div></header><section id="panel" class="content-panel"></section><nav class="bottom-nav">${bottomNav().map(([id,icon,label])=>`<button class="bottom-tab ${tab===id?'active':''}" data-tab="${id}"><b>${icon}</b><span>${label}</span></button>`).join('')}</nav><button class="fab" id="fabCoach">◎</button></section></main>`; $all('[data-tab]').forEach(b=>b.onclick=()=>{tab=b.dataset.tab;render();}); $('#logout').onclick=()=>{auth.profileId=null;tab='login';render();}; $('#fabCoach').onclick=()=>{tab='coach';render();}; pages[tab]?.(); }
function quickStat(label,value){ return `<span class="quick-stat"><small>${esc(label)}</small><b>${esc(value)}</b></span>`; }
function bottomNav(){ return [['dashboard','⌁','Home'],['goals','◎','Goals'],['coach','◉','Coach'],['fuel','◒','Food'],['profile','◈','Profile']]; }
function nav(){ return [['dashboard','⌁ Command Deck'],['goals','◎ Goals + Planner'],['builder','◆ Workout Builder'],['coach','◉ Live Pose Coach'],['health','✚ Health Monitors'],['fuel','◒ Food + Meals'],['route','⌖ GPS Map Routes'],['muscles','◇ Muscle Map'],['timeline','▰ Journey Timeline'],['profile','◈ Profile']]; }
function headline(t){ return {dashboard:'Today’s command center',goals:'Targets, choices, generated plans',builder:'Pick, customize, and launch routines',coach:'MediaPipe pose landmarks, joint angles, rep count',health:'Samsung-style manual + camera health dashboard',fuel:'Food search, calories, recipes, portions',route:'Live GPS map and editable route history',muscles:'Clickable body map',timeline:'Photos, workouts, routes, progress story',profile:'Athlete account and settings'}[t] || 'A-Z Fitness'; }


function renderLogin(){ const has=state.profiles.length>0; const opts=state.profiles.map(x=>`<option value="${x.id}">${esc(x.name||'Unnamed athlete')}</option>`).join(''); $('#app').innerHTML=`<main class="login-wrap"><section class="login-card card glow"><div class="logo-xl">A-Z</div><p class="eyebrow">ATHLETE SETUP</p><h1>${has?'Log in before switching profiles.':'Create your first athlete profile.'}</h1><p class="muted">No placeholder stats. Enter real profile data, then create a 4-digit PIN.</p>${has?`<article class="log"><h3>Existing athlete login</h3><label>Name<select id="who">${opts}</select></label><label>PIN<input id="pin" inputmode="numeric" maxlength="4" type="password" placeholder="PIN"></label><div id="setpin"><p class="tiny">Old starter profiles use first PIN <b>0000</b>, then choose a new PIN.</p><label>New PIN<input id="newpin" inputmode="numeric" maxlength="4" type="password"></label><label>Verify PIN<input id="verpin" inputmode="numeric" maxlength="4" type="password"></label></div><button id="unlock">Unlock athlete</button></article>`:''}<article class="log"><h3>Add athlete profile</h3>${newProfileFields()}<button id="createAthlete">Create athlete + log in</button></article><p id="msg" class="tiny"></p></section></main>`; if(has){ function sync(){ const pr=state.profiles.find(x=>x.id===val('#who')); $('#setpin').hidden=!!pr?.pinHash; } $('#who').onchange=sync; sync(); $('#unlock').onclick=async()=>{ const pr=state.profiles.find(x=>x.id===val('#who')); const pin=val('#pin'); if(!/^\d{4}$/.test(pin)) return $('#msg').textContent='Use a 4 digit PIN.'; if(!pr.pinHash){ if(pin!=='0000') return $('#msg').textContent='First login PIN is 0000.'; if(!/^\d{4}$/.test(val('#newpin')) || val('#newpin')!==val('#verpin')) return $('#msg').textContent='New PINs must match.'; pr.pinHash=await hashPin(val('#newpin')); } else if(await hashPin(pin)!==pr.pinHash){ return $('#msg').textContent='Wrong PIN.'; } auth.profileId=pr.id; tab=profileComplete(pr)?'dashboard':'profile'; render(); cloudLoad().then(()=>render()).catch(()=>{}); }; } $('#createAthlete').onclick=createAthleteFromLogin; }
function newProfileFields(prefix='new'){ return `<label>Name<input id="${prefix}Name" autocomplete="name" placeholder="Athlete name"></label><label>Birthday<input id="${prefix}Birthday" type="date"></label><label>Sex<select id="${prefix}Sex"><option value="">Select</option><option value="male">male</option><option value="female">female</option><option value="other">other / prefer not to say</option></select></label><div class="split"><label>Height ft<input id="${prefix}HeightFt" type="number" min="1" placeholder="5"></label><label>Height in<input id="${prefix}HeightIn" type="number" min="0" max="11" placeholder="8"></label></div><label>Weight lb<input id="${prefix}WeightLb" type="number" min="1" placeholder="150"></label><label>Average weekly workout<select id="${prefix}Level"><option value="">Select</option><option value="low">low</option><option value="medium">medium</option><option value="high">high</option></select></label><label>Goals<input id="${prefix}Goals" placeholder="bulk up, walk, core, yoga"></label><label>Limitations / injuries<textarea id="${prefix}Limitations" placeholder="knees, back, asthma, none"></textarea></label><div class="split"><label>PIN<input id="${prefix}Pin" inputmode="numeric" maxlength="4" type="password"></label><label>Verify PIN<input id="${prefix}Pin2" inputmode="numeric" maxlength="4" type="password"></label></div>`; }
async function createAthleteFromLogin(){ const msg=$('#msg'), p=profile(uuid(),val('#newName').trim()); p.birthday=val('#newBirthday'); p.sex=val('#newSex'); p.heightFt=val('#newHeightFt'); p.heightIn=val('#newHeightIn')||0; p.weightLb=val('#newWeightLb'); p.level=val('#newLevel'); p.goals=val('#newGoals').split(',').map(x=>x.trim()).filter(Boolean); p.limitations=val('#newLimitations'); const pin=val('#newPin'), pin2=val('#newPin2'); if(!profileComplete(p)) return msg.textContent='Fill out name, birthday, sex, height, weight, and weekly workout level.'; if(!/^\d{4}$/.test(pin)||pin!==pin2) return msg.textContent='Create a matching 4-digit PIN.'; p.pinHash=await hashPin(pin); p.onboarding.complete=true; state.profiles.push(p); auth.profileId=p.id; tab='dashboard'; render(); }

const pages = {dashboard,goals,builder,coach,health,fuel,route,muscles,timeline,profile:profilePage};
function dashboard(){ const pr=profileNow(), t=totals(), nut=todayNutrition(), ready=readinessScore(); $('#panel').innerHTML=`<section class="deck-grid"><article class="card hero-gold wide"><p class="eyebrow">TODAY'S ASK</p><h2>What do you want to do?</h2><div class="chips">${goalOptions.map(g=>`<button class="chip" data-goal="${g}">${g}</button>`).join('')}</div><div id="suggestions" class="stack"></div></article><article class="card vitals-card"><h2>True health monitor deck</h2><div class="ring-row">${ring('Readiness',ready,'score')} ${ring('Fuel',calorieTarget(pr)?Math.min(100,Math.round(nut.cal/calorieTarget(pr)*100)):0,'cal')} ${ring('Hydration',waterTarget(pr)?Math.min(100,Math.round(waterOz()/waterTarget(pr)*100)):0,'water')}</div><p class="muted">Readiness blends workout consistency, hydration, food logging, sleep/stress entries, and recovery signals.</p></article><article class="card"><h2>Open data sources</h2><div class="source-list">${openDataSources.map(d=>`<a class="source-pill" href="${d.url}" target="_blank" rel="noreferrer"><b>${d.name}</b><span>${d.use}</span></a>`).join('')}</div></article><article class="card"><h2>Weekly targets</h2>${targetSummary()}</article><article class="card wide"><h2>Progress graph</h2><canvas id="homeChart" height="260"></canvas></article><article class="card wide"><h2>Type-to-generate coach</h2><textarea id="genText" placeholder="Example: I want to bulk up but my knees hurt, I can train 4 days and I ate chicken rice today"></textarea><button id="genBtn">Generate specific plan</button><div id="genOut" class="answer"></div></article></section>`; $all('[data-goal]').forEach(b=>b.onclick=()=>suggestGoal(b.dataset.goal)); $('#genBtn').onclick=()=>generateResponse(val('#genText')); drawChart('homeChart',chartSeries(),['Minutes','Miles x10','Calories/50','Protein/10']); }
function readinessScore(){ const pr=profileNow(); if(!profileComplete(pr)) return 0; const ls=own(state.logs), wt=waterTarget(pr)||1, waterScore=Math.min(30,waterOz()/wt*30), foodScore=own(state.meals).filter(m=>todayKey(m.date)===todayKey()).length?20:0, trainScore=Math.min(30,ls.filter(l=>Date.now()-new Date(l.date).getTime()<7*864e5).length*8), recovery=own(state.metrics).some(m=>/sleep|stress|mindfulness/.test(m.type)&&todayKey(m.date)===todayKey())?20:8; return Math.round(Math.min(100,waterScore+foodScore+trainScore+recovery)); }
function ring(label,value,sub){ const v=Math.max(0,Math.min(100,Number(value)||0)); return `<div class="metric-ring" style="--p:${v}"><span>${v}</span><small>${esc(label)}<br>${esc(sub)}</small></div>`; }
function todayNutrition(){ return own(state.meals).filter(m=>todayKey(m.date)===todayKey()).reduce((a,m)=>{a.cal+=m.cal||0;a.protein+=m.protein||0;a.carbs+=m.carbs||0;a.fat+=m.fat||0;return a;},{cal:0,protein:0,carbs:0,fat:0}); }
function targetSummary(){ const rows=own(state.targets).slice(0,5); return rows.length?rows.map(t=>`<article class="log"><b>${esc(t.name)}</b><span>${t.amount} ${esc(t.unit)} / week • ${esc(t.status||'active')}</span></article>`).join(''):'<p>No targets yet. Open Goals + Planner and add weekly targets.</p>'; }
function suggestGoal(goal){ const list=allWorkouts().filter(w=>(w.goals+' '+w.activity+' '+w.cat).toLowerCase().includes(goal.split(' ')[0])).slice(0,4); $('#suggestions').innerHTML=`<h3>Suggested path for ${esc(goal)}</h3>${(list.length?list:allWorkouts().slice(0,4)).map(w=>`<article class="log"><b>${esc(w.title)}</b><span>${w.cat} • ${w.activity} • ${w.duration} min</span><button data-start="${w.id}">Start step-by-step</button><button data-customize="${w.id}">Customize</button></article>`).join('')}`; $all('[data-start]').forEach(b=>b.onclick=()=>startRoutine(b.dataset.start)); $all('[data-customize]').forEach(b=>b.onclick=()=>{tab='builder';render();setTimeout(()=>loadWorkoutIntoBuilder(b.dataset.customize),0)}); }
function generateResponse(text){ const pr=profileNow(), q=text.toLowerCase(); const foundGoals=goalOptions.filter(g=>q.includes(g.split(' ')[0])||q.includes(g)); const act=activityTypes.find(a=>q.includes(a)); const sore=/knee|back|shoulder|sore|pain/.exec(q)?.[0]; const food=foodDB.find(f=>q.includes(f.name.toLowerCase().split(' ')[0])); const days=(q.match(/\b([1-7])\s*(day|days)/)||[])[1] || ({low:3,medium:4,high:5}[pr.level]); let parts=[]; parts.push(`<b>Plan shaped to your text:</b> ${foundGoals.length?foundGoals.join(', '):'general strength + health'} for ${days} days/week.`); if(act) parts.push(`Primary activity: ${act}. Track it under GPS Map Routes if it moves outside, or Live Pose Coach if it is form-based.`); if(sore) parts.push(`Because you mentioned ${sore}, use lower intensity, add warm-up mobility, and stop if pain spikes. Pick routines tagged mobility/core before high load.`); if(food) parts.push(`Food match: ${food.name} (${food.serving}) ≈ ${food.cal} calories. Add it in Food + Meals so it counts toward ${calorieTarget(pr)} calories/day.`); parts.push(profileComplete(pr)?`Targets: ${proteinTarget(pr)}g protein/day, ${waterTarget(pr)} oz water/day, ${Math.max(2,days-1)} recovery/mobility blocks/week.`:'Finish your profile first so targets are calculated from real stats, not placeholders.'); parts.push(`Next click path: Goals + Planner → Builder → Start step-by-step → Live Pose Coach → Journey Timeline.`); $('#genOut').innerHTML=`<p>${parts.join('</p><p>')}</p>`; }

function goals(){ const pr=profileNow(); $('#panel').innerHTML=`<section class="deck-grid"><article class="card"><h2>Weekly target entry</h2><label>Target name<input id="targetName" placeholder="Miles walked, workouts, protein, sleep, water"></label><div class="split"><label>Amount<input id="targetAmount" type="number" value="3"></label><label>Unit<select id="targetUnit"><option>workouts</option><option>miles</option><option>minutes</option><option>steps</option><option>oz water</option><option>g protein</option><option>hours sleep</option><option>meditations</option></select></label></div><button id="addTarget">Add weekly target</button><div>${targetSummary()}</div></article><article class="card wide"><h2>Goal chooser</h2><p class="muted">Tap any goal; A-Z suggests routines and meal timing.</p><div class="chips">${goalOptions.map(g=>`<button class="chip" data-goalpick="${g}">${g}</button>`).join('')}</div><div id="goalPlan" class="answer"></div></article><article class="card"><h2>Average weekly workout</h2><div class="seg"><button data-load="low">Low</button><button data-load="medium">Medium</button><button data-load="high">High</button></div><p>Current: <b>${pr.level}</b></p></article><article class="card wide"><h2>Activity types</h2><div class="chips">${activityTypes.map(a=>`<button class="chip" data-activity="${a}">${a}</button>`).join('')}</div><div id="activityOut"></div></article></section>`; $('#addTarget').onclick=()=>{state.targets.unshift({id:uuid(),profileId:pr.id,date:new Date().toISOString(),name:val('#targetName')||'Weekly goal',amount:+val('#targetAmount')||1,unit:val('#targetUnit'),status:'active'});render();}; $all('[data-load]').forEach(b=>b.onclick=()=>{pr.level=b.dataset.load;render();}); $all('[data-goalpick]').forEach(b=>b.onclick=()=>{ if(!pr.goals.includes(b.dataset.goalpick)) pr.goals.push(b.dataset.goalpick); $('#goalPlan').innerHTML=planForGoal(b.dataset.goalpick); save(); }); $all('[data-activity]').forEach(b=>b.onclick=()=>{$('#activityOut').innerHTML=activityPlan(b.dataset.activity)}); }
function planForGoal(goal){ const matches=allWorkouts().filter(w=>w.goals.includes(goal.split(' ')[0])); const protein=proteinTarget(), cal=calorieTarget(); return `<h3>${esc(goal)} plan</h3><ol><li>Train ${goal.includes('meditate')?'daily 5-10 minutes':'3-5 days/week'}.</li><li>${cal?`Eat about ${cal} calories/day and ${protein}g protein/day.`:'Finish Profile first so A-Z can calculate calories and protein from real stats.'}</li><li>Use ${matches[0]?.title||'Gold Strength Builder'} first, then log photos and metrics.</li></ol>`; }
function activityPlan(a){ return `<article class="log"><b>${esc(a)} setup</b><span>Use ${['walk','run','hike','bike','kayaking'].includes(a)?'GPS Map Routes with start/stop and saved route':'Workout Builder + Live Pose Coach'}.</span><button data-quickactivity="${a}">Create ${esc(a)} routine</button></article>`; }

function builder(){ $('#panel').innerHTML=`<section class="deck-grid"><article class="card wide"><h2>Pre-built workout library</h2><div class="filter-row"><input id="workoutFilter" placeholder="Filter by core, legs, bike, hike, weights..."><button id="filterBtn">Filter</button><button id="loadWger">Load open-source wger exercises</button></div><p class="tiny">wger is an open-source exercise database. Loaded items can be copied into A-Z routines.</p><div id="workoutList">${allWorkouts().map(workoutCard).join('')}</div><div id="wgerBox"></div></article><article class="card"><h2>Custom workout builder</h2><label>Name<input id="cwName" placeholder="Zayne Gold Core"></label><label>Activity type<select id="cwActivity">${activityTypes.map(a=>`<option>${a}</option>`).join('')}</select></label><label>Muscle focus<input id="cwMuscles" placeholder="core, legs, chest"></label><label>Goal notes<input id="cwGoal" placeholder="bulk, posture, conditioning"></label><label>Exercises<textarea id="cwEx" placeholder="Squat 3x10
Push-up 3x8
Plank 3x30 sec"></textarea></label><button id="saveCustom">Save custom workout</button></article><article class="card wide" id="routineBox"><h2>Step-by-step onboarding preview</h2><p>Pick Start on a workout. The coach walks you exercise by exercise and saves results.</p></article></section>`; wireWorkoutButtons(); $('#filterBtn').onclick=()=>{const q=val('#workoutFilter').toLowerCase(); $('#workoutList').innerHTML=allWorkouts().filter(w=>JSON.stringify(w).toLowerCase().includes(q)).map(workoutCard).join('')||'<p>No matches.</p>'; wireWorkoutButtons();}; $('#loadWger').onclick=loadWgerExercises; $('#saveCustom').onclick=saveCustomWorkout; }
async function loadWgerExercises(){ const q=val('#workoutFilter')||'squat'; const box=$('#wgerBox'); box.innerHTML='<p>Loading wger open-source exercise data...</p>'; try{ const r=await fetch('https://wger.de/api/v2/exerciseinfo/?language=2&limit=12&term='+encodeURIComponent(q)); const j=await r.json(); const rows=(j.results||[]).map(x=>{const t=(x.translations||[]).find(t=>t.name)||{};return{id:x.id,name:t.name||('wger exercise '+x.id),description:(t.description||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim(),muscles:(x.muscles||[]).map(m=>m.name||m.name_en||m.id),equipment:(x.equipment||[]).map(e=>e.name||e.id)}}).filter(x=>x.name); state.wgerCache=rows; box.innerHTML=`<h3>wger exercise catalog results</h3>${rows.map((x,i)=>`<article class="log"><b>${esc(x.name)}</b><span>open-source wger id ${x.id} • muscles ${x.muscles.join(', ')||'listed in wger'}</span><p>${esc(x.description.slice(0,220)||'Exercise instructions available from wger.')}</p><button data-wger="${i}">Copy to custom builder</button></article>`).join('')||'<p>No wger results. Try another search term.</p>'}`; $all('[data-wger]').forEach(b=>b.onclick=()=>{const x=state.wgerCache[+b.dataset.wger]; $('#cwName').value=x.name+' A-Z routine'; $('#cwMuscles').value='wger muscles '+(x.muscles||[]).join(','); $('#cwGoal').value='open source wger exercise'; $('#cwEx').value=x.name+' 3x10\n'+(x.description||'Controlled tempo, clean form');}); save(); }catch(e){ box.innerHTML='<p>wger lookup failed. Local routines still work offline.</p>'; } }
function allWorkouts(){ return [...workouts,...state.customWorkouts]; }
function workoutCard(w){ return `<article class="log"><b>${esc(w.title)}</b><span>${esc(w.cat)} • ${esc(w.activity)} • ${esc(w.load)} • ${w.duration} min</span><p>${esc(w.goals)} • muscles: ${(w.muscles||[]).join(', ')}</p><button data-start="${w.id}">Start</button><button data-loadbuilder="${w.id}">Customize copy</button></article>`; }
function wireWorkoutButtons(){ $all('[data-start]').forEach(b=>b.onclick=()=>startRoutine(b.dataset.start)); $all('[data-loadbuilder]').forEach(b=>b.onclick=()=>loadWorkoutIntoBuilder(b.dataset.loadbuilder)); }
function loadWorkoutIntoBuilder(id){ const w=allWorkouts().find(x=>x.id===id); if(!w)return; $('#cwName')&&($('#cwName').value=w.title+' remix'); $('#cwActivity')&&($('#cwActivity').value=w.activity); $('#cwMuscles')&&($('#cwMuscles').value=(w.muscles||[]).join(', ')); $('#cwGoal')&&($('#cwGoal').value=w.goals); $('#cwEx')&&($('#cwEx').value=w.exercises.map(e=>`${e.name} ${e.sets} ${e.reps}`).join('\n')); }
function saveCustomWorkout(){ const lines=val('#cwEx').split('\n').map(x=>x.trim()).filter(Boolean); const w=plan('custom-'+uuid(),val('#cwName')||'Custom A-Z Routine','Custom',val('#cwGoal')||'custom',profileNow().level,Math.max(10,lines.length*8),val('#cwActivity'),val('#cwMuscles').split(',').map(x=>x.trim()).filter(Boolean),lines.map(x=>ex(x,val('#cwMuscles')||'custom','custom','custom',{type:'custom',angle:'knee',low:75,high:165},['steady tempo','clean posture','controlled breathing']))); state.customWorkouts.unshift(w); tab='builder'; render(); }
function startRoutine(id){ const w=allWorkouts().find(x=>x.id===id)||workouts[0]; state.activeRoutine={id:w.id,step:0,start:Date.now(),reps:0,before:snapshotStats(),photos:[]}; camera.reps=0; camera.events=[]; tab='coach'; render(); }

async function loadPose(){ if(camera.pose) return camera.pose; try{ const m=await import('https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.22/+esm'); const v=await m.FilesetResolver.forVisionTasks('https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.22/wasm'); camera.pose=await m.PoseLandmarker.createFromOptions(v,{baseOptions:{modelAssetPath:'https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_lite/float16/latest/pose_landmarker_lite.task'},runningMode:'VIDEO',numPoses:1}); return camera.pose; }catch(e){ console.warn(e); return null; } }
function coach(){ const r=state.activeRoutine; const w=r?allWorkouts().find(x=>x.id===r.id):allWorkouts()[0]; const step=r?.step||0; const exx=w.exercises[step]||w.exercises[0]; camera.current=exx; $('#panel').innerHTML=`<section class="coach-layout"><article class="card camera-card"><h2>${r?'Step '+(step+1)+' / '+w.exercises.length:'Live Coach'}</h2><h3>${esc(exx.name)}</h3><p>${esc(exx.sets)} • ${esc(exx.reps)} • ${esc(exx.muscles)}</p><div class="video-box"><video id="video" playsinline muted></video><canvas id="overlay" width="960" height="720"></canvas></div><div class="actions"><button id="startCam">Start camera + rep counter</button><button id="prevStep">Prev</button><button id="nextStep">Next step</button><button id="finishRoutine">Finish + save</button></div><p class="cue" id="cue">${exx.cues.map(esc).join(' • ')}</p></article><article class="card"><h2>Live readout</h2><div class="big-reps"><b id="repCount">${camera.reps}</b><span>reps counted</span></div><div id="liveMetrics" class="tile-grid"></div><h3>Joint angles</h3><div id="angles"></div><h3>Pinpoint corrections</h3><div id="events"></div></article></section>`; $('#startCam').onclick=startCamera; $('#nextStep').onclick=()=>{state.activeRoutine??={id:w.id,step:0,start:Date.now(),before:snapshotStats()}; state.activeRoutine.step=Math.min(w.exercises.length-1,(state.activeRoutine.step||0)+1); render();}; $('#prevStep').onclick=()=>{if(state.activeRoutine){state.activeRoutine.step=Math.max(0,(state.activeRoutine.step||0)-1);render();}}; $('#finishRoutine').onclick=finishRoutine; renderLive(); }
async function startCamera(){ const video=$('#video'), cue=$('#cue'); try{ camera.stream=await navigator.mediaDevices.getUserMedia({video:{facingMode:'user',width:{ideal:1280},height:{ideal:720}},audio:false}); video.srcObject=camera.stream; await video.play(); }catch(e){ cue.textContent='Camera blocked: '+e.message; return; } camera.pose=await loadPose(); camera.seconds=0; clearInterval(camera.timer); camera.timer=setInterval(scanFrame,180); }
function pt(lm,i,c){ const q=lm[i]; return {x:q.x*c.width,y:q.y*c.height,z:q.z||0,vis:q.visibility??1}; }
function angle(a,b,c){ const A=Math.atan2(a.y-b.y,a.x-b.x), C=Math.atan2(c.y-b.y,c.x-b.x); let d=Math.abs((A-C)*180/Math.PI); return d>180?360-d:d; }
function scanFrame(){ const video=$('#video'), canvas=$('#overlay'); if(!video||!video.videoWidth)return; const ctx=canvas.getContext('2d'); ctx.clearRect(0,0,canvas.width,canvas.height); ctx.drawImage(video,0,0,canvas.width,canvas.height); let lm=null; if(camera.pose){ try{ lm=camera.pose.detectForVideo(video,performance.now()).landmarks?.[0]; }catch{} } if(lm){ drawPose(ctx,lm,canvas); analyzePose(lm,canvas); } else drawFallback(ctx,canvas); renderLive(); camera.seconds+=.18; }
function drawPose(ctx,lm,c){ const bones=[[11,12],[11,13],[13,15],[12,14],[14,16],[11,23],[12,24],[23,25],[25,27],[24,26],[26,28],[23,24],[27,31],[28,32]]; ctx.strokeStyle='#ffd700'; ctx.lineWidth=5; ctx.shadowColor='#ffd700'; ctx.shadowBlur=10; bones.forEach(([a,b])=>{const A=pt(lm,a,c),B=pt(lm,b,c);ctx.beginPath();ctx.moveTo(A.x,A.y);ctx.lineTo(B.x,B.y);ctx.stroke();}); ctx.shadowBlur=0; ctx.fillStyle='#fff3a3'; [11,12,13,14,15,16,23,24,25,26,27,28].forEach(i=>{const P=pt(lm,i,c);ctx.beginPath();ctx.arc(P.x,P.y,7,0,Math.PI*2);ctx.fill();}); }
function analyzePose(lm,c){ const P=i=>pt(lm,i,c); const A={leftElbow:angle(P(11),P(13),P(15)),rightElbow:angle(P(12),P(14),P(16)),leftKnee:angle(P(23),P(25),P(27)),rightKnee:angle(P(24),P(26),P(28)),leftHip:angle(P(11),P(23),P(25)),rightHip:angle(P(12),P(24),P(26)),shoulderTilt:Math.abs(P(11).y-P(12).y),hipTilt:Math.abs(P(23).y-P(24).y)}; camera.angles=A; const exx=camera.current||{}; let metric=/push|row|curl/i.test(exx.name)?Math.min(A.leftElbow,A.rightElbow):/hip|dead|plank|climber/i.test(exx.name)?Math.min(A.leftHip,A.rightHip):Math.min(A.leftKnee,A.rightKnee); if(metric<105 && camera.open){camera.reps++; camera.open=false;} if(metric>150) camera.open=true; const posture=Math.max(0,Math.min(100,100-(A.shoulderTilt+A.hipTilt)/3)); const breath=estimateBreath(P(11).y,P(12).y); const heart=estimateHeart(); const focus=estimateFocus(lm); camera.metrics={posture:Math.round(posture),breath,heart,focus}; const issues=[]; if(A.shoulderTilt>38) issues.push('level shoulders'); if(A.hipTilt>45) issues.push('square hips'); if(metric<65) issues.push('do not collapse too deep'); if(metric>170 && /squat|lunge|push/i.test(exx.name)) issues.push('unlock joint and control range'); if(issues.length && camera.events.length<25) camera.events.unshift({second:Math.round(camera.seconds),message:issues.join(', '),exercise:exx.name,angles:{...A}}); }
function estimateBreath(y1,y2){ camera.samples.push({t:Date.now(),chest:(y1+y2)/2}); camera.samples=camera.samples.slice(-80); if(camera.samples.length<20)return'calibrating'; const range=Math.max(...camera.samples.map(s=>s.chest))-Math.min(...camera.samples.map(s=>s.chest)); return range>18?'deep/fast':'steady'; }
function estimateHeart(){ return camera.samples.length>30?'camera proxy':'calibrating'; }
function estimateFocus(lm){ const nose=lm[0], l=lm[2], r=lm[5]; if(!nose||!l||!r)return'--'; const spread=Math.abs(l.x-r.x); return spread>.035?'face centered':'check lighting'; }
function drawFallback(ctx,c){ ctx.strokeStyle='#ffd700'; ctx.lineWidth=5; ctx.strokeRect(c.width*.22,c.height*.08,c.width*.56,c.height*.8); ctx.fillStyle='#ffd700'; ctx.font='24px sans-serif'; ctx.fillText('Pose guide loading / fallback',30,c.height-30); camera.metrics={posture:'fallback',breath:'calibrating',heart:'calibrating',focus:'face proxy'}; }
function renderLive(){ $('#repCount')&&($('#repCount').textContent=camera.reps); const h=camera.metrics||{}; $('#liveMetrics')&&($('#liveMetrics').innerHTML=`<div><span>Heart</span><b>${h.heart||'--'}</b></div><div><span>Breath</span><b>${h.breath||'--'}</b></div><div><span>Pupil/focus</span><b>${h.focus||'--'}</b></div><div><span>Posture</span><b>${h.posture||'--'}</b></div>`); $('#angles')&&($('#angles').innerHTML=Object.entries(camera.angles||{}).map(([k,v])=>`<p class="angle-row"><b>${esc(k)}</b><span>${Math.round(v)}°</span></p>`).join('')); $('#events')&&($('#events').innerHTML=camera.events.length?camera.events.slice(0,10).map(e=>`<article class="event"><b>${e.second}s • ${esc(e.exercise||'form')}</b><p>${esc(e.message)}</p></article>`).join(''):'<p>No corrections yet.</p>'); }
function finishRoutine(){ const r=state.activeRoutine, w=allWorkouts().find(x=>x.id===r?.id)||workouts[0]; clearInterval(camera.timer); camera.stream?.getTracks().forEach(t=>t.stop()); state.logs.unshift({id:uuid(),profileId:profileNow().id,planId:w.id,date:new Date().toISOString(),duration:Math.max(1,Math.round((Date.now()-(r?.start||Date.now()))/60000)),activity:w.activity,effort:{low:2,medium:3,high:4}[w.load]||3,steps:0,distanceKm:0,avgHr:null,calories:null,reps:camera.reps,events:camera.events,before:r?.before,after:snapshotStats(),notes:`Completed ${w.title} with ${camera.reps} counted reps.`}); state.activeRoutine=null; camera.reps=0; tab='timeline'; render(); }
function snapshotStats(){ return {weightLb:profileNow().weightLb,waterOz:waterOz(),metrics:own(state.metrics).slice(0,3),time:new Date().toISOString()}; }

function health(){ const latest=latestMetrics(); $('#panel').innerHTML=`<section class="deck-grid"><article class="card wide vitals-card"><h2>Professional health monitor board</h2><p class="muted">Manual entry now; Android Health Connect/Samsung Health native bridge later. Ranges are informational, not diagnosis.</p><div class="monitor-grid">${healthMetrics.slice(0,12).map(m=>monitorTile(m,latest[m])).join('')}</div></article><article class="card wide"><h2>All monitors</h2><div class="chips">${healthMetrics.map(m=>`<button class="chip" data-metric="${m}">${m}</button>`).join('')}</div><div id="metricForm"></div></article><article class="card"><h2>Manual reading helper</h2><div id="metricHelp">Choose a metric to see how to enter or collect it.</div></article><article class="card"><h2>Weather + environment</h2><button id="fetchWeather">Use GPS for weather</button><div id="weatherOut">${weatherSummary()}</div></article><article class="card wide"><h2>Metric history</h2>${own(state.metrics).slice(0,30).map(m=>`<article class="log"><b>${esc(m.type)}: ${esc(m.value)} ${esc(m.unit||'')}</b><span>${new Date(m.date).toLocaleString()} • ${esc(m.note||'')}</span></article>`).join('')||'<p>No health metrics yet.</p>'}</article></section>`; $all('[data-metric]').forEach(b=>b.onclick=()=>metricForm(b.dataset.metric)); $('#fetchWeather').onclick=fetchWeather; }
function latestMetrics(){ const out={}; own(state.metrics).forEach(m=>{out[m.type]??=m}); return out; }
function monitorTile(type,m){ const range=healthRanges[type]||{}; const val=m?`${esc(m.value)} ${esc(m.unit||range.unit||'')}`:'--'; return `<button class="monitor-tile" data-metric="${esc(type)}"><span>${esc(type)}</span><b>${val}</b><small>${esc(range.good||'Tap to log reading/source')}</small></button>`; }
function metricForm(type){ const r=healthRanges[type]||{}; $('#metricForm').innerHTML=`<h3>${esc(type)}</h3><div class="split"><label>Value<input id="metricValue" placeholder="reading"></label><label>Unit<input id="metricUnit" placeholder="${esc(r.unit||'bpm, %, mg/dL, mmHg, hours, score')}"></label></div><label>Notes / source<input id="metricNote" placeholder="Samsung Health, cuff, finger sensor, manual check"></label><button id="saveMetric">Save ${esc(type)}</button>`; $('#metricHelp').innerHTML=metricHelp(type); $('#saveMetric').onclick=()=>{state.metrics.unshift({id:uuid(),profileId:profileNow().id,type,value:val('#metricValue'),unit:val('#metricUnit')||r.unit,note:val('#metricNote'),date:new Date().toISOString()});health();}; }
function metricHelp(t){ const map={steps:'Use phone pedometer/Samsung Health steps, or enter route steps after a walk.', 'blood pressure':'Use a real cuff. Enter systolic/diastolic like 118/76 mmHg.', 'blood oxygen':'Use a pulse oximeter or supported Samsung reading. Enter percent.', 'blood glucose':'Use a glucose meter/CGM; never use the camera for medical glucose.', stress:'Enter Samsung Health stress score or a 1-10 manual rating.', mindfulness:'Log minutes meditated and how you felt.', 'body composition':'Use scale/body comp device; enter weight, body fat %, skeletal muscle if available.', sleep:'Enter hours, quality, bedtime/wake time.', 'heart rate':'Use Samsung Health/watch/chest strap when available. Camera heart is only a rough proxy.', 'antioxidant index':'Enter value from a supported scanner/app if available; otherwise use notes for fruit/vegetable consistency.', 'vascular load':'Enter from compatible monitor/app if available; this PWA cannot medically derive it.'}; return `<p>${esc(map[t]||'Enter the best available reading and source. If the app cannot measure it directly, it keeps the stat with date/time for trend tracking.')}</p>`; }
async function fetchWeather(){ if(!navigator.geolocation)return $('#weatherOut').textContent='Geolocation unavailable.'; navigator.geolocation.getCurrentPosition(async pos=>{ const {latitude,longitude}=pos.coords; try{ const r=await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,relative_humidity_2m,apparent_temperature,uv_index,weather_code,wind_speed_10m&hourly=us_aqi`); const j=await r.json(); const cur=j.current||{}; const row={id:uuid(),profileId:profileNow().id,date:new Date().toISOString(),lat:latitude,lng:longitude,temp:cur.temperature_2m,humidity:cur.relative_humidity_2m,heat:cur.apparent_temperature,uv:cur.uv_index,wind:cur.wind_speed_10m}; state.weather.unshift(row); save(); $('#weatherOut').innerHTML=weatherSummary(); }catch(e){$('#weatherOut').textContent='Weather fetch failed.';} }); }
function weatherSummary(){ const w=own(state.weather)[0]; return w?`<div class="tile-grid"><div><span>Temp</span><b>${w.temp}°C</b></div><div><span>Feels</span><b>${w.heat}°C</b></div><div><span>Humidity</span><b>${w.humidity}%</b></div><div><span>UV</span><b>${w.uv??'--'}</b></div></div>`:'No weather saved yet.'; }
async function searchFoods(q){ const local=foodDB.filter(f=>f.name.toLowerCase().includes(q.toLowerCase())).slice(0,8); try{ const res=await fetch('https://world.openfoodfacts.org/cgi/search.pl?search_terms='+encodeURIComponent(q)+'&search_simple=1&action=process&json=1&page_size=8'); const j=await res.json(); const off=(j.products||[]).map(x=>({name:x.product_name||x.generic_name,serving:x.serving_size||'100 g',cal:Math.round(x.nutriments?.['energy-kcal_100g']||0),protein:Math.round(x.nutriments?.proteins_100g||0),carbs:Math.round(x.nutriments?.carbohydrates_100g||0),fat:Math.round(x.nutriments?.fat_100g||0),source:'Open Food Facts'})).filter(x=>x.name&&x.cal>=0); return [...local,...off].slice(0,12); }catch{return local;} }
function fuel(){ const pr=profileNow(), nut=todayNutrition(), target=calorieTarget(pr); $('#panel').innerHTML=`<section class="deck-grid"><article class="card"><h2>Food + beverage search</h2><label>Type food or drink<input id="foodQ" placeholder="banana, chicken bowl, Gatorade"></label><button id="foodSearch">Find public foods</button><p class="tiny">Uses Open Food Facts public nutrition data plus local whole-food fallback entries.</p><div id="foodResults"></div></article><article class="card vitals-card"><h2>Nutrition dashboard</h2><div class="ring-row">${ring('Calories',Math.min(100,Math.round(nut.cal/(target||1)*100)),nut.cal+'/'+target)} ${ring('Protein',Math.min(100,Math.round(nut.protein/(Math.round(pr.weightLb*.75)||1)*100)),nut.protein+'g')} ${ring('Water',Math.min(100,Math.round(waterOz()/(Math.round(pr.weightLb*.55)||1)*100)),waterOz()+'oz')}</div><div class="macro-bar"><span style="--w:${nut.protein||1};--c:#7dff7a"></span><span style="--w:${nut.carbs||1};--c:#ffd700"></span><span style="--w:${nut.fat||1};--c:#ff9d42"></span></div><p class="tiny">Macro split: protein ${nut.protein}g • carbs ${nut.carbs}g • fat ${nut.fat}g</p></article><article class="card"><h2>Meal plans + recipes</h2><p>Target: <b>${target} calories/day</b> • Protein <b>${Math.round(pr.weightLb*.75)}g</b></p><button id="mealPlan">Generate portions</button><div id="mealOut"></div></article><article class="card"><h2>Water</h2><button data-water="8">+8 oz</button><button data-water="16">+16 oz</button><button data-water="24">+24 oz</button><button data-water="32">+32 oz</button><p>${waterOz()} oz today / target ${waterTarget(pr)||'set profile'} oz</p></article><article class="card wide"><h2>Today intake</h2><div id="mealList"></div></article></section>`; $('#foodSearch').onclick=async()=>showFoodResults(await searchFoods(val('#foodQ'))); $('#mealPlan').onclick=()=>$('#mealOut').innerHTML=mealPlanHtml(pr); $all('[data-water]').forEach(b=>b.onclick=()=>{state.water.unshift({id:uuid(),profileId:pr.id,date:new Date().toISOString(),oz:+b.dataset.water});fuel();}); renderMeals(); }
function showFoodResults(list){ $('#foodResults').innerHTML=list.map((f,i)=>`<article class="log"><b>${esc(f.name)}</b><span>${esc(f.serving)} • ${f.cal} cal • P ${f.protein}g C ${f.carbs}g F ${f.fat}g ${f.source?'• '+f.source:''}</span><div class="split"><label>Amount<input id="amt${i}" type="number" value="1" step=".25"></label><label>Meal<select id="mealType${i}"><option>breakfast</option><option>lunch</option><option>dinner</option><option>snack</option><option>drink</option></select></label></div><button data-food="${i}">Add to diet log</button></article>`).join(''); $all('[data-food]').forEach(b=>b.onclick=()=>{const f=list[+b.dataset.food], m=+val('#amt'+b.dataset.food)||1; state.meals.unshift({id:uuid(),profileId:profileNow().id,date:new Date().toISOString(),meal:val('#mealType'+b.dataset.food),...f,amount:m,cal:Math.round(f.cal*m),protein:Math.round(f.protein*m),carbs:Math.round(f.carbs*m),fat:Math.round(f.fat*m)}); fuel();}); }
function mealPlanHtml(pr){ const c=calorieTarget(pr), protein=proteinTarget(pr); if(!c||!protein) return '<p>Finish Profile first so meal portions use real age, sex, height, weight, and weekly activity.</p>'; return `<ol><li><b>Breakfast ${Math.round(c*.25)} cal:</b> oats + Greek yogurt + fruit. Portion: 1 cup oats, 1 cup yogurt, 1 fruit.</li><li><b>Lunch ${Math.round(c*.30)} cal:</b> chicken/turkey rice bowl. Portion: 4-6 oz protein, 1 cup rice, 2 cups veg.</li><li><b>Pre-workout ${Math.round(c*.12)} cal:</b> banana + milk/yogurt or peanut butter toast 60-90 min before training.</li><li><b>Dinner ${Math.round(c*.28)} cal:</b> salmon/chicken, sweet potato/rice, broccoli. Keep protein high.</li><li><b>Recovery ${Math.round(c*.05)} cal:</b> milk/protein smoothie if daily protein is below ${protein}g.</li></ol><p>Adjust portions up for bulk/strength and down for fat loss while keeping protein steady.</p>`; }
function renderMeals(){ const ms=own(state.meals).filter(m=>todayKey(m.date)===todayKey()); const totals=ms.reduce((a,m)=>{a.cal+=m.cal||0;a.protein+=m.protein||0;a.carbs+=m.carbs||0;a.fat+=m.fat||0;return a;},{cal:0,protein:0,carbs:0,fat:0}); $('#mealList').innerHTML=`<div class="tile-grid"><div><span>Calories</span><b>${totals.cal}</b></div><div><span>Protein</span><b>${totals.protein}g</b></div><div><span>Carbs</span><b>${totals.carbs}g</b></div><div><span>Fat</span><b>${totals.fat}g</b></div></div>`+(ms.map(m=>`<article class="log"><b>${esc(m.meal||'meal')} • ${esc(m.name)}</b><span>${m.amount||1}x • ${m.cal} cal • P ${m.protein} C ${m.carbs} F ${m.fat}</span></article>`).join('')||'<p>No food yet.</p>'); }
function waterOz(){ return own(state.water).filter(w=>todayKey(w.date)===todayKey()).reduce((a,w)=>a+(+w.oz||0),0); }

function route(){ const active=!!routeWatch; $('#panel').innerHTML=`<section class="deck-grid"><article class="card wide"><h2>GPS map route tracker</h2><div class="actions"><button id="startRoute">Start route</button><button id="stopRoute">Stop + save</button><button id="addPoint">Add manual point</button></div><div class="split"><input id="manualLat" placeholder="lat"><input id="manualLng" placeholder="lng"></div><div class="tile-grid"><div><span>Miles</span><b id="routeMiles">0.00</b></div><div><span>Speed</span><b id="routeMph">0.0 mph</b></div><div><span>Points</span><b id="routePts">0</b></div><div><span>Status</span><b>${active?'tracking':'ready'}</b></div></div><div id="map" class="map"><canvas id="routeMap" height="340"></canvas></div><p class="tiny">Map uses OpenStreetMap tiles when online, then draws the route on top.</p></article><article class="card wide"><h2>Saved editable routes</h2>${own(state.routes).map(r=>routeCard(r)).join('')||'<p>No saved routes yet.</p>'}</article></section>`; $('#startRoute').onclick=startRoute; $('#stopRoute').onclick=stopRoute; $('#addPoint').onclick=addManualPoint; drawRouteMap(state.currentRoute?.points||[]); }
function startRoute(){ state.currentRoute={profileId:profileNow().id,date:new Date().toISOString(),points:[],start:Date.now(),activity:'walk/run'}; if(navigator.geolocation){ routeWatch=navigator.geolocation.watchPosition(pos=>{state.currentRoute.points.push({lat:pos.coords.latitude,lng:pos.coords.longitude,t:Date.now(),speed:pos.coords.speed}); updateRouteUI();},{},{enableHighAccuracy:true,maximumAge:1000}); } route(); }
function stopRoute(){ if(routeWatch!=null) navigator.geolocation.clearWatch(routeWatch); routeWatch=null; const pts=state.currentRoute?.points||[], miles=routeMiles(pts), hrs=(Date.now()-(state.currentRoute?.start||Date.now()))/3600000; state.routes.unshift({id:uuid(),profileId:profileNow().id,date:new Date().toISOString(),activity:state.currentRoute?.activity||'route',points:pts,miles,mph:miles/(hrs||1),notes:''}); state.currentRoute=null; route(); }
function addManualPoint(){ state.currentRoute??={profileId:profileNow().id,date:new Date().toISOString(),points:[],start:Date.now(),activity:'manual route'}; const lat=+val('#manualLat'), lng=+val('#manualLng'); if(Number.isFinite(lat)&&Number.isFinite(lng)){state.currentRoute.points.push({lat,lng,t:Date.now(),manual:true}); updateRouteUI();} }
function routeCard(r){ return `<details class="log"><summary><b>${new Date(r.date).toLocaleString()} • ${esc(r.activity)}</b> <span>${r.miles.toFixed(2)} mi • ${r.mph.toFixed(1)} mph • ${r.points.length} points</span></summary><label>Notes<input id="routeNote${r.id}" value="${esc(r.notes||'')}"></label><button onclick="AZ.editRoute('${r.id}')">Save route note</button><button onclick="AZ.deleteRoute('${r.id}')">Delete route</button><canvas class="mini-route" id="mini${r.id}" height="130"></canvas></details>`; }
function routeMiles(pts){ let m=0; for(let i=1;i<pts.length;i++)m+=dist(pts[i-1],pts[i]); return m; }
function dist(a,b){ const R=3958.8,dLat=(b.lat-a.lat)*Math.PI/180,dLon=(b.lng-a.lng)*Math.PI/180,la1=a.lat*Math.PI/180,la2=b.lat*Math.PI/180,h=Math.sin(dLat/2)**2+Math.cos(la1)*Math.cos(la2)*Math.sin(dLon/2)**2; return 2*R*Math.asin(Math.sqrt(h)); }
function updateRouteUI(){ const pts=state.currentRoute.points,m=routeMiles(pts),hrs=(Date.now()-state.currentRoute.start)/3600000; $('#routeMiles')&&($('#routeMiles').textContent=m.toFixed(2)); $('#routeMph')&&($('#routeMph').textContent=(m/(hrs||1)).toFixed(1)+' mph'); $('#routePts')&&($('#routePts').textContent=pts.length); drawRouteMap(pts); }
function drawRouteMap(pts,id='routeMap'){ const c=document.getElementById(id); if(!c)return; const ctx=c.getContext('2d'), w=c.width=c.clientWidth*devicePixelRatio, h=c.height=(+c.getAttribute('height')||320)*devicePixelRatio; ctx.fillStyle='#071007'; ctx.fillRect(0,0,w,h); ctx.strokeStyle='rgba(255,215,0,.16)'; for(let x=0;x<w;x+=60)for(let y=0;y<h;y+=60)ctx.strokeRect(x,y,60,60); if(pts.length){ const center=pts[Math.floor(pts.length/2)]; ctx.fillStyle='rgba(255,255,255,.06)'; ctx.fillText(`OSM center ${center.lat.toFixed(4)}, ${center.lng.toFixed(4)}`,20,22); } if(pts.length<2){ ctx.fillStyle='#ffd700'; ctx.fillText('GPS route draws here live. Manual points work too.',20,50); return; } const minLat=Math.min(...pts.map(p=>p.lat)),maxLat=Math.max(...pts.map(p=>p.lat)),minLng=Math.min(...pts.map(p=>p.lng)),maxLng=Math.max(...pts.map(p=>p.lng)); ctx.strokeStyle='#ffd700'; ctx.lineWidth=5; ctx.beginPath(); pts.forEach((q,i)=>{const x=30+(q.lng-minLng)/((maxLng-minLng)||1)*(w-60), y=h-30-(q.lat-minLat)/((maxLat-minLat)||1)*(h-60); i?ctx.lineTo(x,y):ctx.moveTo(x,y);}); ctx.stroke(); ctx.fillStyle='#fff3a3'; ctx.beginPath(); ctx.arc(30,h-30,8,0,Math.PI*2); ctx.fill(); }
window.AZ={editRoute(id){const r=state.routes.find(x=>x.id===id);if(r){r.notes=document.getElementById('routeNote'+id)?.value||'';save();route();}},deleteRoute(id){state.routes=state.routes.filter(x=>x.id!==id);save();route();}};

function muscles(){ $('#panel').innerHTML=`<section class="deck-grid"><article class="card wide"><h2>Detailed front/back muscle atlas</h2><p class="muted">Tap any zone. The map is original SVG, organized around common anatomy regions and paired with local routines plus wger open-source exercise search.</p><div class="muscle-atlas">${muscleSvg('front')}${muscleSvg('back')}</div></article><article class="card wide"><h2>Muscle area workouts</h2><div id="muscleOut">Tap a gold body zone to see workouts and open-source exercise lookup options.</div></article></section>`; $all('[data-muscle]').forEach(el=>el.onclick=()=>showMuscle(el.dataset.muscle)); }
function muscleSvg(view){ const back=view==='back'; return `<svg class="anatomy" viewBox="0 0 180 320" role="img" aria-label="${view} muscle map"><defs><filter id="glow"><feGaussianBlur stdDeviation="2" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><text x="90" y="18" text-anchor="middle">${back?'BACK':'FRONT'}</text><circle cx="90" cy="42" r="20" class="bone"/><path data-muscle="shoulders" d="M48 75 Q90 50 132 75 L120 98 Q90 80 60 98Z"/><path data-muscle="chest" d="M58 92 Q90 75 122 92 L116 132 Q90 123 64 132Z" class="front-only"/><path data-muscle="back" d="M56 88 Q90 70 124 88 L118 150 Q90 160 62 150Z" class="back-only"/><path data-muscle="core" d="M66 132 L114 132 L121 184 Q90 198 59 184Z"/><path data-muscle="arms" d="M36 82 Q24 128 34 184 L51 180 Q48 125 58 96Z"/><path data-muscle="arms" d="M144 82 Q156 128 146 184 L129 180 Q132 125 122 96Z"/><path data-muscle="glutes" d="M62 184 Q90 204 118 184 L116 220 Q90 238 64 220Z" class="back-only"/><path data-muscle="legs" d="M63 188 Q78 202 82 234 L76 300 L53 300 L53 226Z"/><path data-muscle="legs" d="M117 188 Q102 202 98 234 L104 300 L127 300 L127 226Z"/><path data-muscle="cardio" d="M83 102 q7 -10 14 0 q6 9 -14 25 q-20 -16 -14 -25 q7 -10 14 0z" class="heart"/><text x="90" y="312" text-anchor="middle" class="tiny-svg">tap muscle zones</text></svg>`; }
function showMuscle(id){ const area=muscleAreas.find(x=>x.id===id); const matches=allWorkouts().filter(w=>(w.muscles||[]).includes(id)||JSON.stringify(w).toLowerCase().includes(id)); $('#muscleOut').innerHTML=`<h3>${esc(area?.label||id)}</h3><p>Focus workouts: ${(area?.workouts||[]).join(', ')}</p><div class="actions"><button onclick="document.querySelector('[data-tab=builder]').click(); setTimeout(()=>{document.querySelector('#workoutFilter').value='${esc(id)}'; document.querySelector('#filterBtn').click()},50)">Open builder filtered to ${esc(id)}</button></div>${(matches.length?matches:allWorkouts().slice(0,3)).map(workoutCard).join('')}`; wireWorkoutButtons(); }
function timeline(){ const ls=own(state.logs); $('#panel').innerHTML=`<section class="deck-grid"><article class="card"><h2>Progress photos</h2><label>Before/after/workout photo<input id="photo" type="file" accept="image/*" capture="environment"></label><label>Note<input id="photoNote" placeholder="before workout, after run, posture check"></label><button id="savePhoto">Save photo</button><div class="photo-grid">${own(state.photos).map(x=>`<figure><img src="${x.src}" alt=""><figcaption>${esc(x.note)}<br>${new Date(x.date).toLocaleDateString()}</figcaption></figure>`).join('')}</div></article><article class="card wide"><h2>Clickable history timeline</h2>${ls.map(logCard).join('')||'<p>No workout history yet.</p>'}</article><article class="card wide"><h2>Journey chart</h2><canvas id="journeyChart" height="250"></canvas></article></section>`; $('#savePhoto').onclick=savePhoto; drawChart('journeyChart',chartSeries(),['Minutes','Miles x10','Calories/50','Protein/10']); }
function logCard(l){ const w=allWorkouts().find(x=>x.id===l.planId)||{}; return `<details class="log"><summary><b>${new Date(l.date).toLocaleString()} • ${esc(w.title||l.activity||'Workout')}</b></summary><p>Duration ${l.duration} min • reps ${l.reps||0} • activity ${esc(l.activity||'')} • miles ${((l.distanceKm||0)*.621371).toFixed(2)} • calories ${l.calories||calories(profileNow(),l)}</p><p><b>Before:</b> ${esc(JSON.stringify(l.before||{}))}</p><p><b>After:</b> ${esc(JSON.stringify(l.after||{}))}</p><p><b>Improvements:</b> ${(l.events||[]).map(e=>esc(e.message)).join('; ')||'No correction markers logged.'}</p></details>`; }
function savePhoto(){ const file=$('#photo').files[0]; if(!file)return; const r=new FileReader(); r.onload=()=>{state.photos.unshift({id:uuid(),profileId:profileNow().id,date:new Date().toISOString(),note:val('#photoNote'),src:r.result});timeline();}; r.readAsDataURL(file); }


function profilePage(){ const pr=profileNow(); $('#panel').innerHTML=`<section class="deck-grid"><article class="card wide ${profileComplete(pr)?'':'warning-card'}"><h2>${profileComplete(pr)?'Athlete info':'Required athlete info'}</h2><p class="muted">The app will not calculate calories, protein, water, or training targets from fake placeholders. Save real info here first.</p>${field('name','Name',pr.name)}${field('birthday','Birthday',pr.birthday,'date')}<label>Sex<select id="sex"><option value="">select</option><option value="male" ${pr.sex==='male'?'selected':''}>male</option><option value="female" ${pr.sex==='female'?'selected':''}>female</option><option value="other" ${pr.sex==='other'?'selected':''}>other / prefer not to say</option></select></label><div class="split"><label>Height ft<input id="heightFt" type="number" min="1" value="${esc(pr.heightFt)}"></label><label>Height in<input id="heightIn" type="number" min="0" max="11" value="${esc(pr.heightIn)}"></label></div>${field('weightLb','Weight lb',pr.weightLb,'number')}<label>Average weekly workout<select id="level"><option value="">select</option><option value="low" ${pr.level==='low'?'selected':''}>low</option><option value="medium" ${pr.level==='medium'?'selected':''}>medium</option><option value="high" ${pr.level==='high'?'selected':''}>high</option></select></label><label>Goals<textarea id="goalsText" placeholder="bulk up, walk, core, yoga">${esc((pr.goals||[]).join(', '))}</textarea></label><label>Limitations / injuries<textarea id="limitations">${esc(pr.limitations)}</textarea></label><button id="saveProfile">Save athlete info</button><p id="profileMsg" class="tiny"></p></article><article class="card"><h2>Profile picture + settings</h2><div class="profile-pic">${pr.pic?`<img src="${pr.pic}" alt="">`:'No picture yet'}</div><input id="pic" type="file" accept="image/*"><button id="savePic">Save picture</button><label>Theme<select id="theme"><option value="gold" ${pr.settings.theme==='gold'?'selected':''}>black / yellow / gold</option><option value="midnight" ${pr.settings.theme==='midnight'?'selected':''}>midnight gold</option></select></label><p class="muted">To use another profile, hit Log out, then log into that name with its PIN. No in-app profile switching.</p></article><article class="card wide"><h2>Supabase cloud sync</h2><p>${cloudReady()?cloudStatus:'Cloud sync starts after this athlete has a PIN and complete profile.'}</p><button id="pullCloud">Pull cloud</button><button id="pushCloud">Push cloud</button></article></section>`; $('#saveProfile').onclick=()=>{pr.name=val('#name').trim();pr.birthday=val('#birthday');pr.sex=val('#sex');pr.heightFt=val('#heightFt');pr.heightIn=val('#heightIn')||0;pr.weightLb=val('#weightLb');pr.level=val('#level');pr.goals=val('#goalsText').split(',').map(x=>x.trim()).filter(Boolean);pr.limitations=val('#limitations');pr.onboarding={complete:profileComplete(pr)}; if(!profileComplete(pr)){ $('#profileMsg').textContent='Still missing required profile fields.'; save(); return; } save(); tab='dashboard'; render();}; $('#savePic').onclick=()=>{const file=$('#pic').files[0]; if(!file)return; const r=new FileReader(); r.onload=()=>{pr.pic=r.result;save();profilePage();}; r.readAsDataURL(file);}; $('#theme').onchange=()=>{pr.settings.theme=val('#theme');save();render();}; $('#pullCloud').onclick=async()=>{await cloudLoad();profilePage();}; $('#pushCloud').onclick=async()=>{await cloudSave();profilePage();}; }
function field(id,label,value,type='text'){ return `<label>${label}<input id="${id}" type="${type}" value="${esc(value)}"></label>`; }

function totals(){ const ls=own(state.logs); return {workouts:ls.length,minutes:ls.reduce((a,l)=>a+(+l.duration||0),0),miles:ls.reduce((a,l)=>a+(+l.distanceKm||0),0)*.621371,cal:ls.reduce((a,l)=>a+(l.calories||calories(profileNow(),l)),0)}; }
function calories(pr,l){ if(!profileComplete(pr)) return 0; return Math.round(([2.5,3.5,5,7,9][(l.effort||3)-1]||5)*3.5*weightKg(pr)/200*(l.duration||30)); }
function chartSeries(){ const logs=own(state.logs).slice().reverse().slice(-14); const meals=own(state.meals).slice().reverse().slice(-14); return [{data:logs.map(l=>l.duration||0)},{data:logs.map(l=>(l.distanceKm||0)*6.21371)},{data:logs.map(l=>(l.calories||calories(profileNow(),l))/50)},{data:meals.map(m=>(m.protein||0)/10)}]; }
function drawChart(id,ser,labels){ const c=document.getElementById(id), ctx=c?.getContext('2d'); if(!ctx)return; const w=c.width=c.clientWidth*devicePixelRatio, h=c.height=(+c.getAttribute('height')||240)*devicePixelRatio; ctx.clearRect(0,0,w,h); ctx.strokeStyle='rgba(255,215,0,.18)'; for(let i=1;i<5;i++){ctx.beginPath();ctx.moveTo(35,h*i/5);ctx.lineTo(w-20,h*i/5);ctx.stroke();} const max=Math.max(10,...ser.flatMap(s=>s.data)); ['#ffd700','#fff3a3','#c69200','#7dff7a'].forEach((col,si)=>{const data=ser[si]?.data||[]; ctx.strokeStyle=col; ctx.lineWidth=4; ctx.beginPath(); data.forEach((v,i)=>{const x=40+i*((w-70)/Math.max(1,data.length-1)), y=h-25-v/max*(h-55); i?ctx.lineTo(x,y):ctx.moveTo(x,y);}); ctx.stroke();}); ctx.fillStyle='#ffd700'; ctx.font=`${13*devicePixelRatio}px sans-serif`; labels.forEach((l,i)=>ctx.fillText(l,35+i*135*devicePixelRatio,20*devicePixelRatio)); }

function cloudReady(){ return !!(cloud.supabaseUrl&&cloud.supabaseKey&&auth.profileId&&profileNow().pinHash); }
function cloudHeaders(){ return {'apikey':cloud.supabaseKey,'Authorization':'Bearer '+cloud.supabaseKey,'Content-Type':'application/json','x-az-sync-hash':profileNow().pinHash}; }
function cloudData(){ const id=profileNow().id; return {profiles:state.profiles.filter(x=>x.id===id),logs:own(state.logs),meals:own(state.meals),water:own(state.water),photos:own(state.photos),routes:own(state.routes),targets:own(state.targets),metrics:own(state.metrics),weather:own(state.weather),bodyScans:own(state.bodyScans),wgerCache:state.wgerCache,customWorkouts:state.customWorkouts}; }
function queueCloudSave(){ if(!cloudReady())return; clearTimeout(cloudTimer); cloudTimer=setTimeout(cloudSave,1400); }
async function cloudSave(){ if(!cloudReady())return; try{ cloudStatus='syncing'; const pr=profileNow(); const body=JSON.stringify({profile_id:pr.id,profile_name:pr.name,sync_hash:pr.pinHash,data:cloudData()}); const url=cloud.supabaseUrl+'/rest/v1/azfitness_sync?on_conflict=profile_id,sync_hash'; const r=await fetch(url,{method:'POST',headers:{...cloudHeaders(),'Prefer':'resolution=merge-duplicates'},body}); cloudStatus=r.ok?'cloud synced':'cloud table missing'; }catch(e){ cloudStatus='cloud offline'; } }
async function cloudLoad(){ if(!cloudReady())return; try{ const pr=profileNow(); const url=cloud.supabaseUrl+'/rest/v1/azfitness_sync?profile_id=eq.'+encodeURIComponent(pr.id)+'&select=data,updated_at&limit=1'; const r=await fetch(url,{headers:cloudHeaders()}); const rows=await r.json(); if(rows?.[0]?.data){ mergeCloud(rows[0].data); cloudStatus='cloud loaded'; } }catch(e){ cloudStatus='cloud offline'; } }
function mergeCloud(d){ ['logs','meals','water','photos','routes','targets','metrics','weather','bodyScans'].forEach(k=>{const mine=state[k]||[], incoming=d[k]||[], seen=new Set(mine.map(x=>x.id||JSON.stringify(x))); incoming.forEach(x=>{const id=x.id||JSON.stringify(x); if(!seen.has(id)) mine.push(x);}); state[k]=mine;}); if(d.customWorkouts) state.customWorkouts=[...state.customWorkouts,...d.customWorkouts.filter(w=>!state.customWorkouts.some(x=>x.id===w.id))]; localStorage.setItem(STORAGE_KEY,JSON.stringify(state)); }

render();
